import { defineSignal, setHandler, condition } from '@temporalio/workflow';

export const incrementSignal = defineSignal<[number]>('increment');
export const finishSignal = defineSignal('finish');

export async function CounterWorkflow(): Promise<number> {
  let counter = 0;
  let isDone = false;

  setHandler(incrementSignal, (amount: number) => {
    counter += amount;
  });

  setHandler(finishSignal, () => {
    isDone = true;
  });

  await condition(() => isDone);
  return counter;
}

import { NativeConnection, Worker } from '@temporalio/worker';
import * as workflows from './workflows';

async function run() {
  const address = process.env.TEMPORAL_ADDRESS;
  const namespace = process.env.TEMPORAL_NAMESPACE;
  const apiKey = process.env.TEMPORAL_API_KEY;

  if (!address || !namespace || !apiKey) {
    throw new Error('Missing required environment variables for Temporal Cloud connection');
  }

  const connection = await NativeConnection.connect({
    address,
    tls: {
      auth: {
        apiKey,
      },
    },
  });

  const worker = await Worker.create({
    connection,
    namespace,
    taskQueue: 'counter-ts',
    workflowsPath: require.resolve('./workflows'),
  });

  console.log('Worker started');
  await worker.run();
}

run().catch((err) => {
  console.error(err);
  process.exit(1);
});

import { Connection, Client } from '@temporalio/client';
import { CounterWorkflow, incrementSignal, finishSignal } from './workflows';

async function run() {
  const address = process.env.TEMPORAL_ADDRESS;
  const namespace = process.env.TEMPORAL_NAMESPACE;
  const apiKey = process.env.TEMPORAL_API_KEY;
  const runId = process.env.ZEALT_RUN_ID;

  if (!address || !namespace || !apiKey || !runId) {
    throw new Error('Missing required environment variables');
  }

  const connection = await Connection.connect({
    address,
    tls: {
      auth: {
        apiKey,
      },
    },
  });

  const client = new Client({
    connection,
    namespace,
  });

  const workflowId = `counter-wf-${runId}`;

  const handle = await client.workflow.start(CounterWorkflow, {
    taskQueue: 'counter-ts',
    workflowId,
  });

  console.log(`Started workflow ${workflowId}`);

  await handle.signal(incrementSignal, 5);
  await handle.signal(incrementSignal, 3);
  await handle.signal(incrementSignal, 2);
  await handle.signal(finishSignal);

  const result = await handle.result();
  console.log(result);
}

run().catch((err) => {
  console.error(err);
  process.exit(1);
});

import { spawn } from 'child_process';

async function main() {
  const worker = spawn('npx', ['ts-node', 'src/worker.ts'], {
    stdio: 'inherit',
    env: process.env,
  });

  // Give the worker some time to start
  await new Promise((resolve) => setTimeout(resolve, 5000));

  const client = spawn('npx', ['ts-node', 'src/client.ts'], {
    stdio: 'inherit',
    env: process.env,
  });

  client.on('exit', (code) => {
    worker.kill();
    process.exit(code || 0);
  });
}

main().catch((err) => {
  console.error(err);
  process.exit(1);
});

